mapper.select:
SELECT s.biz_no AS bizNo, s.style_name AS styleName, s.description AS description, s.prompt_summary AS promptSummary, s.prompt AS prompt, s.scope AS scope, s.source_type AS sourceType, s.enable_status AS enableStatus, s.audit_status AS auditStatus, s.created_at AS createdAt FROM u_user_style s WHERE s.source_type = 3 AND s.is_deleted = 0 AND s.enable_status = #{enableStatus}
AND s.style_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY s.id ASC LIMIT #{offset}, #{limit}
